import { ref, onMounted } from 'vue';
import { useRoute } from 'vue-router';
import { supabase, quoteHistoryRepository } from '../supabase';
export default {
  name: 'QuoteDetail',
  setup() {
    const route = useRoute();
    const loading = ref(true);
    const error = ref(null);
    const validating = ref(false);
    const quote = ref(null);
    const quoteItems = ref([]);
    const history = ref([]);
    const loadQuote = async () => {
      try {
        loading.value = true;
        error.value = null;
        const quoteNumber = route.params.quoteNumber;
        const quoteData = await supabase.findByNumber(quoteNumber, true);
        if (!quoteData) {
          throw new Error('Devis introuvable');
        }
        quote.value = quoteData;
        if (quoteData.items) {
          quoteItems.value = quoteData.items;
        }
        history.value = await quoteHistoryRepository.findByQuoteId(quoteData.id);
      } catch (e) {
        error.value = e.message;
      } finally {
        loading.value = false;
      }
    };
    const validateQuote = async () => {
      if (!confirm('Voulez-vous vraiment valider ce devis ?')) return;
      try {
        validating.value = true;
        await supabase.validate(quote.value.quote_number);
        await quoteHistoryRepository.logAction(quote.value.id, 'validated', 'Devis validé par l\'administrateur', 'admin');
        await loadQuote();
      } catch (e) {
        alert('Erreur lors de la validation: ' + e.message);
      } finally {
        validating.value = false;
      }
    };
    const formatDate = dateString => {
      const date = new Date(dateString);
      return date.toLocaleDateString('fr-FR', {
        year: 'numeric',
        month: 'long',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      });
    };
    const formatPrice = price => {
      return parseFloat(price).toFixed(2);
    };
    const getStatusLabel = status => {
      const labels = {
        pending_validation: 'En attente',
        validated: 'Validé',
        expired: 'Expiré',
        converted: 'Converti'
      };
      return labels[status] || status;
    };
    onMounted(() => {
      loadQuote();
    });
    return {
      loading,
      error,
      validating,
      quote,
      quoteItems,
      history,
      validateQuote,
      formatDate,
      formatPrice,
      getStatusLabel
    };
  }
};
